import { ReactNode } from 'react';

import { AuthProvider, useAuth } from './AuthProvider';
import { auth } from 'src/atoms/utils/auth_environment';
import { render, screen, userEvent, waitFor } from 'src/tests/jsdomtest-utils';

// The jsdom setup (msalMock) replaces @azure/msal-browser with an empty stub
// that lacks the enums AuthProviderInner imports (InteractionType, etc.). Use
// the real module here; we override the msalApp instance methods below.
vi.mock('@azure/msal-browser', async (importOriginal) =>
  importOriginal<typeof import('@azure/msal-browser')>()
);

// Fully mock msal-react so AuthProviderInner can render without a real MSAL
// instance (the jsdom setup only mocks MsalProvider).
vi.mock('@azure/msal-react', () => ({
  MsalProvider: ({ children }: { children: ReactNode }) => children,
  useMsal: () => ({
    instance: {
      initialize: vi.fn(() => Promise.resolve()),
      setActiveAccount: vi.fn(),
    },
    accounts: [],
    inProgress: 'none',
  }),
  useMsalAuthentication: () => ({
    login: vi.fn(() => Promise.resolve()),
    result: undefined,
    error: undefined,
    acquireToken: vi.fn(() => Promise.resolve(null)),
  }),
}));

vi.mock('jwt-decode', () => ({
  jwtDecode: () => ({ roles: ['admin'] }),
}));

function Consumer() {
  const { authState, login } = useAuth();
  return (
    <div>
      <span>state: {authState}</span>
      <button onClick={() => login().catch(() => undefined)}>sign in</button>
    </div>
  );
}

beforeEach(() => {
  // Disable mock-auth mode so the real interactive login() path runs.
  vi.stubEnv('VITE_IS_MOCK', 'false');
});

afterEach(() => {
  vi.unstubAllEnvs();
});

test('login() transitions interactionRequired to authorized in place using mock MSAL', async () => {
  // The jsdom setup mocks @azure/msal-browser's PublicClientApplication as an
  // empty class, so we assign the interactive methods we need directly onto
  // the (real) msalApp instance that AuthProvider uses.
  const msalApp = auth.msalApp as unknown as {
    loginPopup: ReturnType<typeof vi.fn>;
    acquireTokenSilent: ReturnType<typeof vi.fn>;
    setActiveAccount: ReturnType<typeof vi.fn>;
  };
  const loginPopup = vi.fn().mockResolvedValue({
    account: { homeAccountId: 'abc', username: 'user@equinor.com' },
  });
  msalApp.loginPopup = loginPopup;
  msalApp.acquireTokenSilent = vi
    .fn()
    .mockResolvedValue({ accessToken: 'token' });
  msalApp.setActiveAccount = vi.fn();

  const user = userEvent.setup();

  render(
    <AuthProvider withoutLoader>
      <Consumer />
    </AuthProvider>
  );

  expect(screen.getByText('state: loading')).toBeInTheDocument();

  await user.click(screen.getByText('sign in'));

  await waitFor(() => expect(loginPopup).toHaveBeenCalled());
  await waitFor(() =>
    expect(screen.getByText('state: authorized')).toBeInTheDocument()
  );
});

import { ReactNode, useState } from 'react';

import {
  AccountInfo,
  InteractionRequiredAuthError,
  InteractionType,
} from '@azure/msal-browser';

import { AuthProviderInner } from './AuthProviderInner';
import { AuthState, MOCK_USER } from './AuthProvider';
import { render, screen, waitFor } from 'src/tests/jsdomtest-utils';

const mocks = vi.hoisted(() => ({
  isInIframe: vi.fn<() => boolean>(() => false),
  login: vi.fn(() => Promise.resolve()),
  acquireToken: vi.fn<(...args: unknown[]) => Promise<unknown>>(() =>
    Promise.resolve(null)
  ),
  error: undefined as unknown,
  result: undefined as unknown,
  accounts: [] as unknown[],
  instance: {
    initialize: vi.fn(() => Promise.resolve()),
    setActiveAccount: vi.fn(),
  },
}));

// The jsdom setup (msalMock) replaces @azure/msal-browser with an empty stub
// that lacks the enums/classes AuthProviderInner imports. Use the real module.
vi.mock('@azure/msal-browser', async (importOriginal) =>
  importOriginal<typeof import('@azure/msal-browser')>()
);

vi.mock('@azure/msal-react', () => ({
  MsalProvider: ({ children }: { children: ReactNode }) => children,
  useMsal: () => ({
    instance: mocks.instance,
    accounts: mocks.accounts,
    inProgress: 'none',
  }),
  useMsalAuthentication: () => ({
    login: mocks.login,
    result: mocks.result,
    error: mocks.error,
    acquireToken: mocks.acquireToken,
  }),
}));

vi.mock('src/atoms/utils/auth_environment', async (importOriginal) => {
  const actual =
    await importOriginal<typeof import('src/atoms/utils/auth_environment')>();
  return {
    ...actual,
    auth: { ...actual.auth, isInIframe: () => mocks.isInIframe() },
  };
});

function Harness({
  initialState = 'loading',
  initialAccount,
}: {
  initialState?: AuthState;
  initialAccount?: typeof MOCK_USER;
}) {
  const [authState, setAuthState] = useState<AuthState>(initialState);
  const [account, setAccount] = useState<AccountInfo | undefined>(
    initialAccount
  );
  const [, setRoles] = useState<string[] | undefined>();
  const [, setPhoto] = useState<string | undefined>();

  return (
    <AuthProviderInner
      account={account}
      setAccount={setAccount}
      setRoles={setRoles}
      setPhoto={setPhoto}
      authState={authState}
      setAuthState={setAuthState}
      withoutLoader={false}
      withoutBackend={false}
    >
      <p>app content</p>
    </AuthProviderInner>
  );
}

beforeEach(() => {
  mocks.isInIframe.mockReturnValue(false);
  mocks.error = undefined;
  mocks.result = undefined;
  mocks.accounts = [];
  mocks.login.mockClear();
  mocks.acquireToken.mockReset().mockResolvedValue(null);
  mocks.instance.initialize.mockClear();
  mocks.instance.setActiveAccount.mockClear();
});

test('iframe + initial silent InteractionRequiredAuthError renders children (interactionRequired)', async () => {
  mocks.isInIframe.mockReturnValue(true);
  mocks.error = new InteractionRequiredAuthError();

  render(<Harness />);

  expect(await screen.findByText('app content')).toBeInTheDocument();
  expect(mocks.login).not.toHaveBeenCalled();
});

test('iframe + roles-step InteractionRequiredAuthError renders children (interactionRequired)', async () => {
  mocks.isInIframe.mockReturnValue(true);
  mocks.acquireToken.mockRejectedValue(new InteractionRequiredAuthError());

  render(<Harness initialAccount={MOCK_USER} />);

  expect(await screen.findByText('app content')).toBeInTheDocument();
  expect(mocks.login).not.toHaveBeenCalled();
});

test('non-iframe + InteractionRequiredAuthError triggers redirect login', async () => {
  mocks.isInIframe.mockReturnValue(false);
  mocks.error = new InteractionRequiredAuthError();

  render(<Harness />);

  await waitFor(() =>
    expect(mocks.login).toHaveBeenCalledWith(
      InteractionType.Redirect,
      expect.anything()
    )
  );
});

test('non-iframe + non-interaction roles error renders MissingAccessToApp (unauthorized)', async () => {
  mocks.isInIframe.mockReturnValue(false);
  mocks.acquireToken.mockRejectedValue(new Error('boom'));

  render(<Harness initialAccount={MOCK_USER} />);

  expect(await screen.findByText(/don't have access/i)).toBeInTheDocument();
  expect(screen.queryByText('app content')).not.toBeInTheDocument();
});

import { ReactNode } from 'react';

import { QueryClient, QueryClientProvider } from '@tanstack/react-query';

import { AuthState } from './AuthProvider/AuthProvider';
import { LoadingProvider } from './LoadingProvider';
import { render, screen } from 'src/tests/browsertest-utils';

const mocks = vi.hoisted(() => ({
  authState: 'loading' as AuthState,
}));

vi.mock('src/providers/AuthProvider/AuthProvider', () => ({
  useAuth: () => ({ authState: mocks.authState }),
}));

const wrapper = ({ children }: { children: ReactNode }) => (
  <QueryClientProvider client={new QueryClient()}>
    {children}
  </QueryClientProvider>
);

test('renders children (pass-through) when authState is interactionRequired', () => {
  mocks.authState = 'interactionRequired';

  render(
    <LoadingProvider>
      <p>app content</p>
    </LoadingProvider>,
    { wrapper }
  );

  expect(screen.getByText('app content')).toBeInTheDocument();
  expect(screen.queryByRole('progressbar')).not.toBeInTheDocument();
});

test('renders the full-page spinner (not children) when loading', () => {
  mocks.authState = 'loading';

  render(
    <LoadingProvider>
      <p>app content</p>
    </LoadingProvider>,
    { wrapper }
  );

  expect(screen.queryByText('app content')).not.toBeInTheDocument();
  expect(screen.getByTestId('app-icon-svg')).toBeInTheDocument();
});

test('renders the full-page spinner (not children) when unauthorized', () => {
  mocks.authState = 'unauthorized';

  render(
    <LoadingProvider>
      <p>app content</p>
    </LoadingProvider>,
    { wrapper }
  );

  expect(screen.queryByText('app content')).not.toBeInTheDocument();
  expect(screen.getByTestId('app-icon-svg')).toBeInTheDocument();
});

